1. You may include auxiliary/helper code before or after the required signature.
2. All import/include statements (e.g., `import` in Python, `#include` in C/C++) must be placed at the very top of the file.
3. Preserve the provided signature exactly as given. Do not modify parameter names, types, or return types.
4. Ensure the final code is complete, self-contained, and directly runnable.
5. Return ONLY the raw code. Do not include explanations, markdown backticks, or conversational text.

You are generating Go code. Only generate the required function. DO NOT generate main function.
The reference solution of that problem in Typescript is 
function solve(s: string): number {
    const n = s.length;
    const prefix_L = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix_L[i + 1] = prefix_L[i] + (s[i] === 'L' ? 1 : 0);
    }

    const suffix_T = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        suffix_T[i] = suffix_T[i + 1] + (s[i] === 'T' ? 1 : 0);
    }

    let original_count = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === 'C') {
            const l_before = prefix_L[i];
            const t_after = suffix_T[i + 1];
            original_count += l_before * t_after;
        }
    }

    let insert_L_increase = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === 'C') {
            insert_L_increase += suffix_T[i + 1];
        }
    }

    let insert_T_increase = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === 'C') {
            insert_T_increase += prefix_L[i];
        }
    }

    let insert_C_increase = 0;
    for (let i = 0; i <= n; i++) {
        const val = prefix_L[i] * suffix_T[i];
        if (val > insert_C_increase) {
            insert_C_increase = val;
        }
    }

    const max_increase = Math.max(insert_L_increase, insert_T_increase, insert_C_increase);
    return original_count + max_increase;
}

