    for i := 0; i < n; i++ {
        if s[i] == 'C' {
            l_before := prefix_L[i]
            t_after := suffix_T[i+1]
            original_count += l_before * t_after
        }
    }
    insert_L_increase := 0
    for i := 0; i < n; i++ {
        if s[i] == 'C' {
            insert_L_increase += suffix_T[i+1]
        }
    }
    insert_T_increase := 0
    for i := 0; i < n; i++ {
        if s[i] == 'C' {
            insert_T_increase += prefix_L[i]
        }
    }
    insert_C_increase := 0
    max_val := 0
    for i := 0; i <= n; i++ {
        current := prefix_L[i] * suffix_T[i]
        if current > max_val {
            max_val = current
        }
